data.content:
**MSTest does not have `Assert.IsGreaterThan` or `Assert.IsInRange`.** Those don't exist in the MSTest assertion API. Here's what you can use instead:

| Need | MSTest Approach |
|---|---|
| Greater/less than | `Assert.IsTrue(val > x)` — but poor failure messages |
| Equality | `Assert.AreEqual(expected, actual)` |
| Float tolerance | `Assert.AreEqual(expected, actual, delta)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

For better comparison assertions, consider **FluentAssertions** (`actual.Should().BeGreaterThan(x)`, `actual.Should().BeInRange(lo, hi)`).

Here's a test class using what MSTest actually provides:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ReturnsExpected(int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_TotalZero_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundary tests ──────────────────────────

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.999, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    // ── NormalizeScore ────────────────────────────────────

    [TestMethod]
    public void NormalizeScore_CapsAt100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NormalCase()
    {
        Assert.AreEqual(50.0, _calc.NormalizeScore(25, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }
}
```

**Key takeaways:**
- Use **`Assert.AreEqual(expected, actual, delta)`** for floating-point comparisons — the `delta` parameter handles precision
- Use **`Assert.ThrowsException<T>`** for boundary validation that should throw
- Use **`[DataRow]`** to cover boundary values concisely (e.g., 89.999 vs 90.0)
- If you need `BeGreaterThan`/`BeInRange` style assertions, add the **FluentAssertions** NuGet package
